class Solution {
public:
    int longestIncreasingSubsequence(vector<int>& nums) {
        if (nums.size() == 0) return 0;
        vector<int> dp(nums.size(), 1);
        for (int i = 0; i < nums.size(); i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] > nums[j]) {
                    dp[i] = max(dp[i], dp[j] + 1);
                }
            }
        }
        int maxLen = 0;
        for (int i = 0; i < nums.size(); i++) {
            maxLen = max(maxLen, dp[i]);
        }
        return maxLen;
    }
};

int main() {
    // Test case 1
    vector<int> nums = {10, 9, 2, 5, 3, 7, 101, 18};
    Solution solution;
    int result = solution.longestIncreasingSubsequence(nums);
    cout << "Expected: 4, Actual: " << result << endl;

    // Test case 2
    nums = {4, 10, 4, 3, 8, 9};
    result = solution.longestIncreasingSubsequence(nums);
    cout << "Expected: 3, Actual: " << result << endl;

    return 0;
}

